## src/services/authService.ts

```typescript
import { UserProfile } from '../types';

/**
 * SERVICE D'AUTHENTIFICATION & SÉCURITÉ (SIMULATION BACKEND)
 * 
 * Simule:
 * - Hachage bcrypt
 * - Envoi/Vérification SMS
 * - Rate Limiting
 */

// --- 1. CRYPTOGRAPHIE (Simulation bcrypt) ---

// Simule le hachage d'un PIN (Hashage asynchrone)
export const hashPin = async (pin: string): Promise<string> => {
  // Délai artificiel pour simuler le coût CPU de bcrypt
  await new Promise(resolve => setTimeout(resolve, 300));

  // Création d'un hash simulé (Ne jamais faire ça en prod, utiliser une vraie lib bcrypt côté serveur)
  const salt = "apnet_salt_v1";
  return `bcrypt_sim_${btoa(pin + salt)}`;
};

// Simule la vérification (Compare hash)
export const verifyPin = async (inputPin: string, storedHash: string): Promise<boolean> => {
  await new Promise(resolve => setTimeout(resolve, 500)); // Délai anti-timing attack
  const generatedHash = await hashPin(inputPin);
  // Dans une vraie simulation bcrypt, le sel est inclus dans le hash, ici on simplifie
  // On compare ce qu'on vient de générer avec ce qui est stocké (en assumant le même algo déterministe pour la simu)
  // Pour la simulation, on recalcule le hash théorique de l'input
  const salt = "apnet_salt_v1";
  const expectedHash = `bcrypt_sim_${btoa(inputPin + salt)}`;

  return storedHash === expectedHash;
};

// --- 2. SMS SERVICE (Simulation) ---

const verificationCodes = new Map<string, string>();

export const sendSmsCode = async (phoneNumber: string): Promise<boolean> => {
    await new Promise(resolve => setTimeout(resolve, 1500)); // Délai réseau

    // Génère un code à 4 chiffres
    const code = Math.floor(1000 + Math.random() * 9000).toString();
    verificationCodes.set(phoneNumber, code);

    // SIMULATION : On affiche le code car on ne peut pas envoyer de vrai SMS
    console.log(`[SMS GATEWAY] Code pour ${phoneNumber}: ${code}`);
    alert(`CODE VÉRIFICATION APNET : ${code}\n\n(Ce code simule un SMS reçu sur ${phoneNumber})`);

    return true;
};

export const verifySmsCode = async (phoneNumber: string, code: string): Promise<boolean> => {
    await new Promise(resolve => setTimeout(resolve, 1000)); // Délai vérification
    const storedCode = verificationCodes.get(phoneNumber);

    // Code maître pour tests : 1234
    if (code === '1234') return true;

    if (storedCode === code) {
        verificationCodes.delete(phoneNumber);
        return true;
    }
    return false;
};

// --- 3. SÉCURITÉ & RATE LIMITING ---

const MAX_ATTEMPTS = 3;
let attempts = 0;
let lockUntil = 0;

export const checkRateLimit = (): { allowed: boolean; waitTime?: number } => {
  const now = Date.now();
  if (now < lockUntil) {
    return { allowed: false, waitTime: Math.ceil((lockUntil - now) / 1000) };
  }
  return { allowed: true };
};

export const registerFailedAttempt = (): { remaining: number; locked: boolean } => {
  attempts++;
  if (attempts >= MAX_ATTEMPTS) {
    lockUntil = Date.now() + 30000; // Bloqué 30 secondes
    attempts = 0;
    return { remaining: 0, locked: true };
  }
  return { remaining: MAX_ATTEMPTS - attempts, locked: false };
};

export const resetAttempts = () => {
  attempts = 0;
  lockUntil = 0;
};
```

