```typescript
import React, { useState } from "react";
import { Lock, AlertTriangle, Loader2, KeyRound, Phone, ArrowRight, UserPlus } from "lucide-react";
import { checkRateLimit, registerFailedAttempt, resetAttempts } from "../services/authService";

interface PinLoginPageProps {
  onPinSubmit: (phone: string, pin: string) => Promise<boolean>;
  onGoToRegister: () => void;
}

export const PinLoginPage: React.FC<PinLoginPageProps> = ({ onPinSubmit, onGoToRegister }) => {
  const [phone, setPhone] = useState("");
  const [pin, setPin] = useState("");
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [lockedWaitTime, setLockedWaitTime] = useState(0);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    // 1. Check Security
    const limitStatus = checkRateLimit();
    if (!limitStatus.allowed) {
        setLockedWaitTime(limitStatus.waitTime || 30);
        setError(`Trop de tentatives. Réessayez dans ${limitStatus.waitTime}s.`);
        return;
    }

    // 2. Validate
    if (phone.length < 8) {
        setError("Numéro de téléphone invalide.");
        return;
    }
    if (pin.length < 4) {
      setError("Code PIN invalide (4 chiffres min).");
      return;
    }

    setIsLoading(true);

    try {
        // 3. API Call
        const success = await onPinSubmit(phone, pin);

        if (success) {
            resetAttempts();
            // Redirect handled by parent
        } else {
            const attemptStatus = registerFailedAttempt();
            if (attemptStatus.locked) {
                setLockedWaitTime(30);
                setError("Compte temporairement bloqué (sécurité).");
            } else {
                setError("Numéro ou Code PIN incorrect.");
            }
            setPin(""); // Reset PIN only
        }
    } catch (err) {
        setError("Erreur de connexion. Vérifiez votre réseau.");
    } finally {
        setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 p-4 font-sans">

      {/* Brand Header */}
      <div className="mb-10 text-center animate-in fade-in slide-in-from-top-5 duration-500">
        <h1 className="text-6xl font-extrabold tracking-tighter mb-2">
          <span className="text-brand-green">AP</span>
          <span className="text-brand-orange">NET</span>
        </h1>
        <p className="text-gray-500 font-medium tracking-wide">Votre plateforme de services</p>
      </div>

      {/* Login Card */}
      <div className="bg-white p-8 rounded-3xl shadow-xl w-full max-w-sm border border-gray-100 relative overflow-hidden">

        {/* Status Bar */}
        <div className={`absolute top-0 left-0 w-full h-1.5 ${lockedWaitTime > 0 ? 'bg-red-500' : 'bg-gradient-to-r from-brand-green to-brand-orange'}`}></div>

        <h2 className="text-2xl font-bold text-gray-900 mb-6 flex items-center gap-2">
           <span className="bg-brand-green/10 p-2 rounded-full text-brand-green"><Lock size={20}/></span>
           Connexion
        </h2>

        <form onSubmit={handleSubmit} className="space-y-5">

          {/* Phone Input */}
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-500 uppercase ml-1">Numéro de téléphone</label>
            <div className="relative group">
                <span className="absolute left-4 top-3.5 text-gray-900 font-bold border-r border-gray-300 pr-3">+225</span>
                <input
                    type="tel"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value.replace(/[^0-9]/g, ''))}
                    disabled={lockedWaitTime > 0 || isLoading}
                    placeholder="0707070707"
                    className="w-full pl-20 pr-4 py-3.5 bg-gray-50 border-2 border-transparent rounded-xl font-bold text-lg text-gray-900 focus:bg-white focus:border-brand-green focus:outline-none transition-all placeholder-gray-300"
                />
            </div>
          </div>

          {/* PIN Input */}
          <div className="space-y-1">
            <label className="text-xs font-bold text-gray-500 uppercase ml-1">Votre Code PIN</label>
            <input
                type="password"
                inputMode="numeric"
                maxLength={6}
                value={pin}
                onChange={(e) => setPin(e.target.value.replace(/[^0-9]/g, ''))}
                disabled={lockedWaitTime > 0 || isLoading}
                placeholder="••••"
                className="w-full px-4 py-3.5 bg-gray-50 border-2 border-transparent rounded-xl font-extrabold text-2xl text-center text-gray-900 tracking-[0.5em] focus:bg-white focus:border-brand-orange focus:outline-none transition-all placeholder-gray-300"
            />
          </div>

          {/* Error Message */}
          {error && (
            <div className="bg-red-50 text-red-600 text-sm py-3 px-4 rounded-xl border border-red-100 flex items-center gap-2 animate-pulse">
                <AlertTriangle size={18} className="flex-shrink-0" />
                <span className="font-medium">{error}</span>
            </div>
          )}

          {/* Submit Button */}
          <button 
            type="submit" 
            disabled={lockedWaitTime > 0 || isLoading || phone.length < 8 || pin.length < 4}
            className={`w-full py-4 rounded-xl font-bold text-white text-lg shadow-lg flex items-center justify-center gap-2 transition-all transform active:scale-[0.98] ${
                lockedWaitTime > 0 
                ? 'bg-gray-400 cursor-not-allowed' 
                : 'bg-brand-green hover:bg-green-700'
            }`}
          >
            {isLoading ? <Loader2 className="animate-spin" /> : <>Se connecter <ArrowRight size={20}/></>}
          </button>
        </form>

        <div className="mt-6 text-center">
            <button className="text-sm text-gray-400 font-medium hover:text-brand-orange transition">
                Code PIN oublié ?
            </button>
        </div>
      </div>

      {/* Register Link */}
      <div className="mt-8 text-center animate-in fade-in slide-in-from-bottom-5 duration-700">
         <p className="text-gray-500 font-medium mb-3">Nouvel utilisateur ?</p>
         <button 
            onClick={onGoToRegister}
            className="bg-white text-brand-orange px-8 py-3 rounded-full font-bold shadow-md hover:shadow-lg transition flex items-center gap-2 mx-auto border border-orange-100"
         >
            <UserPlus size={18} /> Créer un compte
         </button>
      </div>
    </div>
  );
};
```

## src/components/RegistrationForm.tsx

```typescript
import React, { useState } from 'react';
import { UserRole, UserProfile } from '../types';
import { hashPin, sendSmsCode, verifySmsCode } from '../services/authService';
import { ABIDJAN_COMMUNES, SERVICE_CATEGORIES } from '../constants';
import { Loader2, CheckCircle, ShieldCheck, MapPin, User, Briefcase, ArrowLeft } from 'lucide-react';

interface RegistrationFormProps {
  onRegister: (newUser: UserProfile) => void;
  onCancel: () => void;
}

export const RegistrationForm: React.FC<RegistrationFormProps> = ({ onRegister, onCancel }) => {
  // Unified State for the form
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    phone: '',
    pin: '',
    confirmPin: '',
    role: UserRole.PROVIDER,
    city: 'Abidjan',
    commune: '',
    category: '',
    subCategory: ''
  });

  const [step, setStep] = useState<'FORM' | 'SMS_VERIFY'>('FORM');
  const [smsCode, setSmsCode] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  // 1. Validation du formulaire initial
  const handleValidateForm = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Validation Basic
    if (!formData.firstName || !formData.lastName || !formData.phone) {
        setError("Veuillez remplir votre Nom, Prénom et Numéro.");
        return;
    }
    if (formData.pin.length < 4 || formData.pin !== formData.confirmPin) {
        setError("Le PIN doit faire 4 à 6 chiffres et être confirmé à l'identique.");
        return;
    }
    if (formData.city === 'Abidjan' && !formData.commune) {
        setError("Veuillez sélectionner votre commune.");
        return;
    }

    setIsProcessing(true);

    // Déclenchement envoi SMS
    try {
        await sendSmsCode(formData.phone);
        setStep('SMS_VERIFY');
    } catch (err) {
        setError("Erreur lors de l'envoi du SMS.");
    } finally {
        setIsProcessing(false);
    }
  };

  // 2. Vérification SMS et Création Compte
  const handleVerifySms = async (e: React.FormEvent) => {
      e.preventDefault();
      setError('');
      setIsProcessing(true);

      const isValid = await verifySmsCode(formData.phone, smsCode);

      if (!isValid) {
          setError("Code SMS incorrect. Réessayez.");
          setIsProcessing(false);
          return;
      }

      // Hachage du PIN avant stockage
      const pinHash = await hashPin(formData.pin);

      // Création de l'objet utilisateur
      const newUser: UserProfile = {
          id: `u_${Date.now()}`,
          role: formData.role,
          firstName: formData.firstName,
          lastName: formData.lastName,
          phone: formData.phone,
          whatsapp: formData.phone, // Par défaut
          verified: true, // Vérifié par SMS
          location: {
              city: formData.city,
              commune: formData.commune || undefined,
              quartier: 'Non précisé'
          },
          photoUrl: `https://ui-avatars.com/api/?name=${formData.firstName}+${formData.lastName}&background=random`,
          description: "Nouveau membre APNET",
          pinHash: pinHash, // Sécurisé

          // Métier (si prestataire)
          category: formData.role === UserRole.PROVIDER ? formData.category : undefined,
          subCategory: formData.role === UserRole.PROVIDER ? formData.subCategory : undefined,
          jobTitle: formData.role === UserRole.PROVIDER ? (formData.subCategory || 'Prestataire') : undefined,

          // Defaults
          walletBalance: 0,
          transactions: [],
          rating: 5,
          reviewCount: 0,
          completedJobs: 0
      };

      // Finalisation
      setTimeout(() => {
          onRegister(newUser);
          setIsProcessing(false);
      }, 500);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">

        {/* Container */}
        <div className="bg-white w-full max-w-lg rounded-3xl shadow-xl overflow-hidden border border-gray-100 flex flex-col">

            {/* Header */}
            <div className="bg-brand-green p-6 text-white text-center relative">
                {step === 'FORM' && (
                    <button onClick={onCancel} className="absolute left-4 top-6 text-green-100 hover:text-white">
                        <ArrowLeft size={24} />
                    </button>
                )}
                <h2 className="text-2xl font-extrabold tracking-tight">Inscription APNET</h2>
                <p className="text-green-100 text-sm mt-1">
                    {step === 'FORM' ? 'Créez votre compte sécurisé' : 'Vérification du numéro'}
                </p>
            </div>

            {/* FORMULAIRE PRINCIPAL */}
            {step === 'FORM' && (
                <form onSubmit={handleValidateForm} className="p-6 md:p-8 space-y-6 animate-in fade-in slide-in-from-right">

                    {/* Role Selector */}
                    <div className="flex bg-gray-100 p-1 rounded-xl">
                        <button type="button" onClick={() => setFormData({...formData, role: UserRole.PROVIDER})} className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition ${formData.role === UserRole.PROVIDER ? 'bg-white text-brand-orange shadow-sm' : 'text-gray-500'}`}>
                            Je suis Prestataire
                        </button>
                        <button type="button" onClick={() => setFormData({...formData, role: UserRole.SEEKER})} className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition ${formData.role === UserRole.SEEKER ? 'bg-white text-brand-green shadow-sm' : 'text-gray-500'}`}>
                            Je suis Client
                        </button>
                    </div>

                    {/* Identité */}
                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-gray-500 mb-1">PRÉNOM</label>
                                <input type="text" className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:bg-white focus:border-brand-green outline-none font-medium" 
                                    value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} placeholder="Jean" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-500 mb-1">NOM</label>
                                <input type="text" className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:bg-white focus:border-brand-green outline-none font-medium" 
                                    value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} placeholder="Kouassi" />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-gray-500 mb-1">TÉLÉPHONE (Identifiant)</label>
