import { UserProfile, UserRole } from '../types';

/**
 * SERVICE D'AUTHENTIFICATION & SÉCURITÉ (SIMULATION BACK-END)
 * 
 * Simule une API Node.js avec:
 * - Hachage de mot de passe (bcrypt simulation)
 * - Envoi de SMS (Gateway simulation)
 * - Vérification de connexion sécurisée
 */

// --- 1. SIMULATION BASE DE DONNÉES ---
// Dans une vraie app, c'est MongoDB ou PostgreSQL.
const MOCK_DB_USERS = new Map<string, any>(); 

// --- 2. CRYPTOGRAPHIE (Simulation bcrypt) ---

const SALT_ROUNDS = 10;

// Simule le hachage : bcrypt.hash(pin, 10)
export const hashPin = async (pin: string): Promise<string> => {
  // Simulation délai CPU (hachage)
  await new Promise(resolve => setTimeout(resolve, 300));
  return `bcrypt_hash_${btoa(pin)}_secure`;
};

// Simule la vérification : bcrypt.compare(plain, hash)
export const verifyPin = async (inputPin: string, storedHash: string): Promise<boolean> => {
  await new Promise(resolve => setTimeout(resolve, 300)); // Délai anti-timing
  const computedHash = `bcrypt_hash_${btoa(inputPin)}_secure`;
  return computedHash === storedHash;
};

// --- 3. SMS GATEWAY (Simulation) ---

const verificationCodes = new Map<string, string>();

export const sendSmsCode = async (phoneNumber: string): Promise<string> => {
    await new Promise(resolve => setTimeout(resolve, 1000)); // Délai réseau

    // Génération code 4 chiffres
    const code = Math.floor(1000 + Math.random() * 9000).toString();
    verificationCodes.set(phoneNumber, code);

    console.log(`[SMS API] Envoi à ${phoneNumber} : Code ${code}`);

    // Dans la réalité, on appelle l'API SMS ici. Pour la démo, on retourne le code pour l'afficher.
    return code; 
};

export const verifySmsCode = async (phoneNumber: string, code: string): Promise<boolean> => {
    await new Promise(resolve => setTimeout(resolve, 800)); // Délai réseau

    const stored = verificationCodes.get(phoneNumber);
    // Code "1234" toujours valide pour les tests
    if (code === '1234') return true;

    if (stored && stored === code) {
        verificationCodes.delete(phoneNumber);
        return true;
    }
    return false;
};

// --- 4. RATE LIMITING (Sécurité) ---

const loginAttempts = new Map<string, { count: number, lockUntil: number }>();

export const checkRateLimit = (phoneNumber: string): { allowed: boolean, wait?: number } => {
    const record = loginAttempts.get(phoneNumber);
    if (!record) return { allowed: true };

    const now = Date.now();
    if (now < record.lockUntil) {
        return { allowed: false, wait: Math.ceil((record.lockUntil - now) / 1000) };
    }
    return { allowed: true };
};

export const registerAttempt = (phoneNumber: string, success: boolean) => {
    if (success) {
        loginAttempts.delete(phoneNumber);
        return;
    }

    const record = loginAttempts.get(phoneNumber) || { count: 0, lockUntil: 0 };
    record.count += 1;

    if (record.count >= 3) {
        record.lockUntil = Date.now() + 60000; // Bloqué 1 minute
        record.count = 0; // Reset count après blocage
    }

    loginAttempts.set(phoneNumber, record);
};

// --- 5. API ENDPOINTS SIMULÉS ---

export const apiRegister = async (userData: any): Promise<{ success: boolean, user?: UserProfile, error?: string }> => {
    // Check if user exists (Simulation)
    // Ici on accepte tout nouvel utilisateur pour la démo

    const pinHash = await hashPin(userData.pin);

    const newUser: UserProfile = {
        id: `user_${Date.now()}`,
        role: UserRole.PROVIDER, // Default
        firstName: userData.firstName,
        lastName: userData.lastName,
        phone: userData.phone,
        whatsapp: userData.phone,
        location: { city: 'Abidjan', quartier: 'Non précisé' },
        verified: true, // Validé par SMS
        description: "Nouveau membre",
        pinHash: pinHash, // Stockage sécurisé
        photoUrl: `https://ui-avatars.com/api/?name=${userData.firstName}+${userData.lastName}&background=random`,
        walletBalance: 0,
        transactions: []
    };

    return { success: true, user: newUser };
};
