                        Continuer <ArrowRight size={20} />
                    </button>

                    <button type="button" onClick={onCancel} className="w-full text-gray-400 font-bold text-sm py-2">
                        J'ai déjà un compte
                    </button>
                </form>
            )}

            {/* STEP 2: PIN */}
            {step === 'PIN' && (
                <form onSubmit={handlePinSubmit} className="space-y-6 animate-in slide-in-from-right">
                    <div className="text-center mb-6">
                        <Lock className="w-12 h-12 text-brand-orange mx-auto bg-orange-50 p-2 rounded-full mb-2" />
                        <h3 className="font-bold text-gray-800">Sécurisez votre compte</h3>
                        <p className="text-xs text-gray-500">Créez un code secret à 4 chiffres.</p>
                    </div>

                    <div className="space-y-4">
                        <input 
                            type="password" placeholder="Code PIN (4 chiffres)" maxLength={4} required
                            className="w-full p-4 bg-gray-50 border-none rounded-xl text-center text-3xl font-extrabold tracking-[0.5em] focus:ring-2 focus:ring-brand-orange"
                            value={pin} onChange={e => setPin(e.target.value.replace(/[^0-9]/g, ''))}
                        />
                        <input 
                            type="password" placeholder="Confirmer le PIN" maxLength={4} required
                            className="w-full p-4 bg-gray-50 border-none rounded-xl text-center text-3xl font-extrabold tracking-[0.5em] focus:ring-2 focus:ring-brand-orange"
                            value={confirmPin} onChange={e => setConfirmPin(e.target.value.replace(/[^0-9]/g, ''))}
                        />
                    </div>

                    <button type="submit" disabled={isLoading} className="w-full bg-brand-orange text-white font-bold py-4 rounded-xl shadow-lg hover:bg-orange-600 transition flex justify-center items-center gap-2">
                        {isLoading ? <Loader2 className="animate-spin" /> : "Valider le PIN"}
                    </button>
                </form>
            )}

            {/* STEP 3: SMS VERIFY */}
            {step === 'SMS' && (
                <form onSubmit={handleSmsSubmit} className="space-y-6 animate-in slide-in-from-right">
                    <div className="text-center mb-6">
                        <ShieldCheck className="w-12 h-12 text-blue-600 mx-auto bg-blue-50 p-2 rounded-full mb-2" />
                        <h3 className="font-bold text-gray-800">Vérification</h3>
                        <p className="text-xs text-gray-500">
                            Entrez le code envoyé au <br/> 
                            <span className="font-bold text-gray-900">+225 {formData.phone}</span>
                        </p>
                    </div>

                    <div>
                        <input 
                            type="text" maxLength={4} autoFocus
                            className="w-full p-4 bg-transparent border-b-4 border-gray-200 focus:border-brand-green text-center text-4xl font-extrabold tracking-[0.5em] outline-none"
                            value={smsCode} onChange={e => setSmsCode(e.target.value.replace(/[^0-9]/g, ''))}
                            placeholder="----"
                        />
                    </div>

                    <button type="submit" disabled={isLoading || smsCode.length < 4} className="w-full bg-brand-green text-white font-bold py-4 rounded-xl shadow-lg hover:bg-green-700 transition flex justify-center items-center gap-2 disabled:opacity-50">
                        {isLoading ? <Loader2 className="animate-spin" /> : "Confirmer et Accéder"}
                    </button>

                    <p className="text-center text-xs text-gray-400 mt-4 cursor-pointer hover:text-brand-orange">
                        Renvoyer le code SMS
                    </p>
                </form>
            )}

        </div>
      </div>
    </div>
  );
};
