import React, { useState } from 'react';
import { checkRateLimit, registerAttempt, verifyPin } from '../services/authService';
import { Loader2, Phone, Lock, ArrowRight, AlertTriangle } from 'lucide-react';

interface PinLoginPageProps {
  onPinSubmit: (phone: string, pin: string) => Promise<boolean>;
  onGoToRegister: () => void;
}

export const PinLoginPage: React.FC<PinLoginPageProps> = ({ onPinSubmit, onGoToRegister }) => {
  const [phone, setPhone] = useState('');
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [lockTime, setLockTime] = useState(0);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // 1. Check Security Rate Limit
    const limit = checkRateLimit(phone);
    if (!limit.allowed && limit.wait) {
        setLockTime(limit.wait);
        setError(`Trop de tentatives. Réessayez dans ${limit.wait}s.`);
        return;
    }

    // 2. Validate
    if (phone.length < 8 || pin.length < 4) {
        setError("Veuillez remplir correctement les champs.");
        return;
    }

    setIsLoading(true);

    try {
        // 3. Authenticate
        const success = await onPinSubmit(phone, pin);

        if (!success) {
            registerAttempt(phone, false); // Log failure
            const newLimit = checkRateLimit(phone);
            if (!newLimit.allowed && newLimit.wait) {
                setLockTime(newLimit.wait);
                setError(`Compte bloqué temporairement (${newLimit.wait}s).`);
            } else {
                setError("Numéro ou Code PIN incorrect.");
            }
            setPin('');
        } else {
            registerAttempt(phone, true); // Reset failure count on success
        }
    } catch (err) {
        setError("Erreur de connexion serveur.");
    } finally {
        setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col justify-center items-center p-4">

        {/* Branding */}
        <div className="mb-10 text-center animate-in fade-in slide-in-from-top-5">
            <h1 className="text-5xl font-extrabold tracking-tighter mb-2">
                <span className="text-brand-green">AP</span>
                <span className="text-brand-orange">NET</span>
            </h1>
            <p className="text-gray-400 font-medium tracking-wide text-sm uppercase">Services & Emploi</p>
        </div>

        <div className="w-full max-w-sm bg-white rounded-3xl shadow-xl p-8 border border-gray-100 relative overflow-hidden">

            {/* Status Bar */}
            <div className={`absolute top-0 left-0 w-full h-2 ${lockTime > 0 ? 'bg-red-500' : 'bg-gradient-to-r from-brand-green to-brand-orange'}`}></div>

            <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center gap-2">
                <Lock size={20} className={lockTime > 0 ? "text-red-500" : "text-brand-green"} />
                Connexion
            </h2>

            <form onSubmit={handleSubmit} className="space-y-5">

                {/* Phone Input */}
                <div className="relative group">
                    <label className="text-xs font-bold text-gray-400 uppercase ml-1 mb-1 block">Votre Numéro</label>
                    <span className="absolute left-4 top-[34px] text-gray-900 font-bold border-r border-gray-300 pr-3">+225</span>
                    <input
                        type="tel"
                        disabled={lockTime > 0}
                        className="w-full pl-20 pr-4 py-3.5 bg-gray-50 border-2 border-transparent rounded-xl font-bold text-lg text-gray-900 focus:bg-white focus:border-brand-green focus:outline-none transition-all placeholder-gray-300"
                        placeholder="0707070707"
                        value={phone}
                        onChange={e => setPhone(e.target.value.replace(/[^0-9]/g, ''))}
                    />
                </div>

                {/* PIN Input */}
                <div>
                    <label className="text-xs font-bold text-gray-400 uppercase ml-1 mb-1 block">Votre Code Secret</label>
                    <input
                        type="password"
                        maxLength={4}
                        disabled={lockTime > 0}
                        className="w-full text-center py-3.5 bg-gray-50 border-2 border-transparent rounded-xl font-extrabold text-3xl text-gray-900 tracking-[0.5em] focus:bg-white focus:border-brand-orange focus:outline-none transition-all placeholder-gray-300"
                        placeholder="••••"
                        value={pin}
                        onChange={e => setPin(e.target.value.replace(/[^0-9]/g, ''))}
                    />
                </div>

                {error && (
                    <div className="bg-red-50 text-red-600 text-sm py-3 px-4 rounded-xl border border-red-100 flex items-center gap-2 animate-pulse">
                        <AlertTriangle size={18} className="flex-shrink-0" />
                        <span className="font-bold">{error}</span>
                    </div>
                )}

                <button 
                    type="submit" 
                    disabled={lockTime > 0 || isLoading || phone.length < 8 || pin.length < 4}
                    className={`w-full py-4 rounded-xl font-bold text-white text-lg shadow-lg flex items-center justify-center gap-2 transition-all transform active:scale-[0.98] ${
                        lockTime > 0 
                        ? 'bg-gray-400 cursor-not-allowed' 
                        : 'bg-brand-green hover:bg-green-700'
                    }`}
                >
                    {isLoading ? <Loader2 className="animate-spin" /> : "Se connecter"}
                </button>
            </form>

            <div className="mt-8 text-center pt-6 border-t border-gray-100">
                <p className="text-gray-400 text-sm mb-3">Nouvel utilisateur ?</p>
                <button 
                    onClick={onGoToRegister}
                    className="text-brand-orange font-bold hover:underline"
                >
                    Créer un compte maintenant
                </button>
            </div>
        </div>
    </div>
  );
};
